const { execSync } = require('child_process');
const data = $input.item.json;
const val = (data.query && data.query.pr_number) ? data.query.pr_number : data.pr_number;
if (!val) { return [{ json: { stdout: '', stderr: 'No pr_number provided. Got: ' + JSON.stringify(data) } }]; }
try {
  // Defaulting to squash and deleting branch upon merge
  const cmd = 'gh pr merge ' + val + ' --squash --delete-branch';
  const stdout = execSync(cmd, { encoding: 'utf8', timeout: 30000 });
  return [{ json: { stdout: stdout || 'Done.', stderr: '' } }];
} catch(e) {
  return [{ json: { stdout: e.stdout || '', stderr: e.stderr || e.message } }];
}
